import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import './SignUp.css';

function SignUp() {
    const [username, setUsername] = useState('');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const navigate = useNavigate();

    const handleSignUp = () => {
        // Here, you would typically make an API call to create a new user.
        // For simplicity, we'll just check if all fields are filled and save the user to a CSV file.
        if (username && email && password) {
            const user = { id: Date.now(), username, email, password };
            const csvLine = `${user.id},${user.username},${user.email},${user.password}\n`;

            // Append the new user to the CSV file.
            // In a real application, you would use a server-side script to handle this.
            const link = document.createElement('a');
            link.href = URL.createObjectURL(new Blob([csvLine], { type: 'text/csv' }));
            link.download = 'users.csv';
            link.click();

            // Navigate to the sign in page.
            navigate('/signin');
        } else {
            alert('Please fill in all fields.');
        }
    };

    return (
        <div className="signup-container">
            <h2>Sign Up</h2>
            <input
                type="text"
                placeholder="Username"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
            />
            <input
                type="email"
                placeholder="Email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
            />
            <input
                type="password"
                placeholder="Password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
            />
            <button onClick={handleSignUp}>Sign Up</button>
        </div>
    );
}

export default SignUp;
